import jwt
from datetime import datetime, timedelta, timezone
from functools import wraps
from flask import request, abort, g
from config import JWT_PRIVATE_KEY_PATH, JWT_PUBLIC_KEY_PATH, JWT_ALGORITHM, JWT_EXPIRY_SECONDS

_private_key = open(JWT_PRIVATE_KEY_PATH).read()
_public_key = open(JWT_PUBLIC_KEY_PATH).read()

def _make_token(user):
    payload = {
        'sub': str(user.id),
        'role': user.role,
        'exp': datetime.now(timezone.utc) + timedelta(seconds=JWT_EXPIRY_SECONDS),
    }
    return jwt.encode(payload, _private_key, algorithm=JWT_ALGORITHM)

def login(username, password):
    user = db.get_user(username)
    if not user or not user.check_password(password):
        return None
    return user, _make_token(user)

def logout():
    pass  # stateless — client discards token

def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.headers.get('Authorization', '')
        if not auth.startswith('Bearer '):
            abort(401)
        token = auth[7:]
        try:
            payload = jwt.decode(token, _public_key, algorithms=[JWT_ALGORITHM])
        except jwt.ExpiredSignatureError:
            abort(401)
        except jwt.InvalidTokenError:
            abort(401)
        g.user_id = payload['sub']
        g.role = payload['role']
        return f(*args, **kwargs)
    return decorated
